def t(key: str, lang: str = DEFAULT_LANG) -> str:
    """
    Devuelve la traducción de `key` para el idioma `lang`.
    Si el idioma no existe, cae a español.
    Si la clave no existe, devuelve la clave entre corchetes (útil para debug).
    """
    entry = TRANSLATIONS.get(key)
    if entry is None:
        return f'[{key}]'
    return entry.get(lang) or entry.get(DEFAULT_LANG) or f'[{key}]'


def get_all_for_lang(lang: str) -> Dict[str, str]:
    """
    Devuelve un diccionario plano {key: valor} para el idioma dado.
    Útil para serializar a JSON y enviarlo al cliente.
    """
    result = {}
    for key, variants in TRANSLATIONS.items():
        result[key] = variants.get(lang) or variants.get(DEFAULT_LANG) or f'[{key}]'
    return result
